export interface CompactCollege {
  name: string;
  state: string;
  city: string;
  type: "Public" | "Private" | "Government" | "Deemed";
  uniName: string;
  estYear: number;
  rating: number;
  accreditation: string[];
  desc: string;
  students: number;
  campusSize: string;
  courseNames: string[];
  scholarshipNames: string[];
  entrance: string;
  category: string;
  hostelFee: string;
  messFee: string;
  annualFee: string;
  avgAnnualFee: string;
  avgSalary: number;
  placementPct: number;
  highestSalary: number;
  recruitersCount: number;
  studentsInternships: number;
  avgStipend: number;
  ppoRate: number;
  alumniF500: number;
  alumniEntrepreneurs: number;
  alumniAbroad: number;
  admissionFaqs: { question: string; answer: string }[];
}

/* ═══════════════════════════════════════════════════════
   HELPER
   ═══════════════════════════════════════════════════════ */

function c(template: any, data: any): CompactCollege {
  return { ...template, ...data } as CompactCollege;
}

